// A module to create a boolean expression tree

// Define a class to represent a node in the tree
class Node {
    public var left:Node;
    public var right:Node;
    public var operator:String;
    public var value:String;

    public function new(left:Node, right:Node, operator:String, value:String) {
        this.left = left;
        this.right = right;
        this.operator = operator;
        this.value = value;
    }

    // Evaluate the node and return a boolean value
    public function eval():Bool {
        switch(operator) {
            case "and":
                return left.eval() && right.eval();
            case "or":
                return left.eval() || right.eval();
            case "not":
                return !left.eval();
            case "true":
                return true;
            case "false":
                return false;
            default:
                // Invalid operator
                throw new Error("Invalid operator");
        }
    }
}

// Define a class to build the tree
class TreeBuilder {
    // Parse an expression and return a node representing the root of the tree
    public static function build(expression:String):Node {
        // Split the expression into tokens
        var tokens:Array<String> = expression.split(" ");

        // Build the tree recursively
        return buildHelper(tokens);
    }

    // Helper function to build the tree recursively
    private static function buildHelper(tokens:Array<String>):Node {
        // Base case: no more tokens
        if(tokens.length == 0) {
            throw new Error("Empty expression");
        }

        // Get the next token
        var token:String = tokens.shift();

        // Check for boolean literals
        if(token == "true" || token == "false") {
            return new Node(null, null, token, null);
        }

        // Check for negation
        if(token == "not") {
            var child:Node = buildHelper(tokens);
            return new Node(child, null, token, null);
        }

        // Check for binary operators
        if(token == "and" || token == "or") {
            var left:Node = buildHelper(tokens);
            var right:Node = buildHelper(tokens);
            return new Node(left, right, token, null);
        }

        // Invalid token
        throw new Error("Invalid token");
    }
}

// Define a class to test the tree
class Test {
    public static function main() {
        // Test an expression with only one boolean literal
        var expression:String = "true";
        var root:Node = TreeBuilder.build(expression);
        var result:Bool = root.eval();
        assert result == true : "Test 1 failed";

        // Test an expression with negation
        expression = "not true";
        root = TreeBuilder.build(expression);
        result = root.eval();
        assert result == false : "Test 2 failed";

        // Test an expression with binary operators
        expression = "true and false";
        root = TreeBuilder.build(expression);
        result = root.eval();
        assert result == false : "Test 3 failed";

        expression = "false or true";
