    input: process.stdin,
    output: process.stdout
});

// Prompt function to ask for input
function prompt(question) {
    return new Promise((resolve, reject) => {
        rl.question(question, (answer) => {
            resolve(answer.trim());
        });
    });
}

// Function to copy a file or directory recursively
function copyFileOrDirectory(src, dest) {
    if (fs.existsSync(src)) {
        if (fs.lstatSync(src).isDirectory()) {
            if (!fs.existsSync(dest)) {
                fs.mkdirSync(dest);
            }
            const files = fs.readdirSync(src);
            files.forEach((file) => {
                copyFileOrDirectory(path.join(src, file), path.join(dest, file));
            });
        } else {
            fs.copyFileSync(src, dest);
        }
    }
}

// Function to rename a file or directory
function renameFileOrDirectory(src, dest) {
    if (fs.existsSync(src)) {
        fs.renameSync(src, dest);
    }
}

// Function to delete a file or directory recursively
function deleteFileOrDirectory(src) {
    if (fs.existsSync(src)) {
        if (fs.lstatSync(src).isDirectory()) {
            const files = fs.readdirSync(src);
            files.forEach((file) => {
                deleteFileOrDirectory(path.join(src, file));
            });
            fs.rmdirSync(src);
        } else {
            fs.unlinkSync(src);
        }
    }
}

