    ListNode *head = NULL;

    add_node(&head, 1);
    add_node(&head, 2);
    add_node(&head, 3);
    add_node(&head, 4);
    add_node(&head, 5);

    printf("Linked List: ");
    print_list(head);

    return 0;
}
